files.content:
:host {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
}

.conversation-list {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
}

.conversation-list__content {
  position: relative;
  flex: 1 1 auto;
  min-height: 0;
  overflow: auto;
  padding: var(--dimension-space-100);
  padding-bottom: calc(var(--dimension-size-600) + var(--dimension-size-100));
  box-sizing: border-box;
}

.conversation-list__empty {
  display: contents;
}

.conversation-list__actions {
  position: absolute;
  right: var(--dimension-space-200);
  bottom: var(--dimension-space-200);
  z-index: var(--dimension-z-index-floating);
}

.conversation-list__actions-surface {
  display: flex;
  border-radius: var(--dimension-radius-half);
  box-shadow: var(--effect-elevation-elevated-floating);
}

.conversation-list__actions-surface:empty {
  display: none;
}

import { Component, h, Host } from '@stencil/core';

@Component({
  tag: 'ds-conversation-list',
  styleUrl: 'ConversationList.css',
  scoped: true,
})
export class ConversationList {
  render() {
    return (
      <Host>
        <div class="conversation-list">
          <div class="conversation-list__content">
            <slot />
            <div class="conversation-list__empty">
              <slot name="empty" />
            </div>
          </div>
          <div class="conversation-list__actions">
            <div class="conversation-list__actions-surface">
              <slot name="actions" />
            </div>
          </div>
        </div>
      </Host>
    );
  }
}
